from itertools import product

def verify_law(law_func, num_vars, law_name):
    """
    Verify a Boolean law by testing all possible inputs.
    """
    # Generate all possible input combinations
    for values in product([0, 1], repeat=num_vars):
        lhs, rhs = law_func(*values)
        if lhs != rhs:
            print(f"    Failed for inputs {values}: {lhs} != {rhs}")
            return False
    return True

# Define laws to verify
def identity_or(a):
    """A + 0 = A"""
    return (a | 0, a)

def identity_and(a):
    """A · 1 = A"""
    return (a & 1, a)

def complement_or(a):
    """A + Ā = 1"""
    return (a | (1-a), 1)

def complement_and(a):
    """A · Ā = 0"""
    return (a & (1-a), 0)

def demorgan_or(a, b):
    """NOT(A + B) = NOT(A) · NOT(B)"""
    lhs = 1 - (a | b)
    rhs = (1-a) & (1-b)
    return (lhs, rhs)

def demorgan_and(a, b):
    """NOT(A · B) = NOT(A) + NOT(B)"""
    lhs = 1 - (a & b)
    rhs = (1-a) | (1-b)
    return (lhs, rhs)

def distributive_or(a, b, c):
    """A + (B · C) = (A + B) · (A + C)"""
    lhs = a | (b & c)
    rhs = (a | b) & (a | c)
    return (lhs, rhs)

def distributive_and(a, b, c):
    """A · (B + C) = (A · B) + (A · C)"""
    lhs = a & (b | c)
    rhs = (a & b) | (a & c)
    return (lhs, rhs)

def absorption(a, b):
    """A + AB = A"""
    lhs = a | (a & b)
    rhs = a
    return (lhs, rhs)

def consensus(a, b, c):
    """AB + A'C + BC = AB + A'C"""
    lhs = (a & b) | ((1-a) & c) | (b & c)
    rhs = (a & b) | ((1-a) & c)
    return (lhs, rhs)

# Test all laws
laws = [
    (identity_or, 1, "Identity (OR): A + 0 = A"),
    (identity_and, 1, "Identity (AND): A · 1 = A"),
    (complement_or, 1, "Complement (OR): A + Ā = 1"),
    (complement_and, 1, "Complement (AND): A · Ā = 0"),
    (demorgan_or, 2, "De Morgan (OR): NOT(A+B) = NOT(A)·NOT(B)"),
    (demorgan_and, 2, "De Morgan (AND): NOT(A·B) = NOT(A)+NOT(B)"),
    (distributive_or, 3, "Distributive (OR): A+(B·C) = (A+B)·(A+C)"),
    (distributive_and, 3, "Distributive (AND): A·(B+C) = A·B+A·C"),
    (absorption, 2, "Absorption: A + AB = A"),
    (consensus, 3, "Consensus: AB + A'C + BC = AB + A'C"),
]

print("Verifying Boolean Laws:")
for law_func, num_vars, name in laws:
    result = verify_law(law_func, num_vars, name)
    status = "✓ VALID" if result else "✗ INVALID"
    print(f"  {status}: {name}")

from itertools import product

def minterm(variables, values):
    """
    Create a minterm (product term) string.
    For SOP: variable appears as-is if value=1, complemented if value=0
    """
    terms = []
    for var, val in zip(variables, values):
        if val == 1:
            terms.append(var)
        else:
            terms.append(f"{var}'")
    return "".join(terms)

def maxterm(variables, values):
    """
    Create a maxterm (sum term) string.
    For POS: variable appears complemented if value=1, as-is if value=0
    """
    terms = []
    for var, val in zip(variables, values):
        if val == 0:
            terms.append(var)
        else:
            terms.append(f"{var}'")
    return "(" + "+".join(terms) + ")"

def truth_table_to_sop(func, variables):
    """
    Convert a Boolean function to Sum of Products form.
    """
    minterms = []

    for values in product([0, 1], repeat=len(variables)):
        var_dict = dict(zip(variables, values))
        if func(var_dict) == 1:
            minterms.append(minterm(variables, values))

    if not minterms:
        return "0"
    return " + ".join(minterms)

def truth_table_to_pos(func, variables):
    """
    Convert a Boolean function to Product of Sums form.
    """
    maxterms = []

    for values in product([0, 1], repeat=len(variables)):
        var_dict = dict(zip(variables, values))
        if func(var_dict) == 0:
            maxterms.append(maxterm(variables, values))

    if not maxterms:
        return "1"
    return "".join(maxterms)

# Test functions
def xor_func(v):
    return v['A'] ^ v['B']

def and_func(v):
    return v['A'] & v['B']

def or_func(v):
    return v['A'] | v['B']

def majority_func(v):
    """Returns 1 if majority of inputs are 1"""
    return 1 if (v['A'] + v['B'] + v['C']) >= 2 else 0

vars2 = ['A', 'B']
vars3 = ['A', 'B', 'C']

print("=== Two-variable functions ===")

print("\nXOR function (A⊕B):")
print(f"  SOP: {truth_table_to_sop(xor_func, vars2)}")
print(f"  POS: {truth_table_to_pos(xor_func, vars2)}")

print("\nAND function (A·B):")
print(f"  SOP: {truth_table_to_sop(and_func, vars2)}")
print(f"  POS: {truth_table_to_pos(and_func, vars2)}")

print("\nOR function (A+B):")
print(f"  SOP: {truth_table_to_sop(or_func, vars2)}")
print(f"  POS: {truth_table_to_pos(or_func, vars2)}")

print("\n=== Three-variable function ===")
print("\nMajority function:")
print(f"  SOP: {truth_table_to_sop(majority_func, vars3)}")
print(f"  POS: {truth_table_to_pos(majority_func, vars3)}")

class BooleanCircuit:
    """
    Represent and analyze Boolean circuits.
    """

    def __init__(self, name):
        self.name = name
        self.gates = []

    def add_not(self, input_wire, output_wire):
        self.gates.append(('NOT', [input_wire], output_wire))

    def add_and(self, inputs, output_wire):
        self.gates.append(('AND', list(inputs), output_wire))

    def add_or(self, inputs, output_wire):
        self.gates.append(('OR', list(inputs), output_wire))

    def add_nand(self, inputs, output_wire):
        self.gates.append(('NAND', list(inputs), output_wire))

    def add_xor(self, inputs, output_wire):
        self.gates.append(('XOR', list(inputs), output_wire))

    def gate_count(self):
        counts = {}
        for gate_type, _, _ in self.gates:
            counts[gate_type] = counts.get(gate_type, 0) + 1
        return counts

    def total_gates(self):
        return len(self.gates)

    def evaluate(self, inputs):
        wires = dict(inputs)

        for gate_type, gate_inputs, output in self.gates:
            input_vals = [wires[i] for i in gate_inputs]

            if gate_type == 'NOT':
                wires[output] = 1 - input_vals[0]
            elif gate_type == 'AND':
                wires[output] = 1 if all(v == 1 for v in input_vals) else 0
            elif gate_type == 'OR':
                wires[output] = 1 if any(v == 1 for v in input_vals) else 0
            elif gate_type == 'NAND':
                wires[output] = 0 if all(v == 1 for v in input_vals) else 1
            elif gate_type == 'XOR':
                wires[output] = input_vals[0] ^ input_vals[1]

        return wires

    def compare(self, other):
        print(f"\nComparing {self.name} vs {other.name}:")
        print(f"  {self.name}: {self.total_gates()} gates {self.gate_count()}")
        print(f"  {other.name}: {other.total_gates()} gates {other.gate_count()}")

        diff = self.total_gates() - other.total_gates()
        if diff > 0:
            print(f"  {other.name} saves {diff} gates")
        elif diff < 0:
            print(f"  {self.name} saves {-diff} gates")
        else:
            print(f"  Same gate count")

# Build circuits for XOR

# Circuit 1: SOP implementation A'B + AB'
circ1 = BooleanCircuit("XOR SOP")
circ1.add_not('A', 'A_not')
circ1.add_not('B', 'B_not')
circ1.add_and(['A_not', 'B'], 't1')
circ1.add_and(['A', 'B_not'], 't2')
circ1.add_or(['t1', 't2'], 'out')

# Circuit 2: NAND-only implementation (4 NANDs)
circ2 = BooleanCircuit("XOR NAND-only")
circ2.add_nand(['A', 'B'], 'n1')  # NAND(A,B)
circ2.add_nand(['A', 'n1'], 'n2')  # NAND(A, NAND(A,B))
circ2.add_nand(['B', 'n1'], 'n3')  # NAND(B, NAND(A,B))
circ2.add_nand(['n2', 'n3'], 'out')  # Final NAND

# Circuit 3: Using XOR directly
circ3 = BooleanCircuit("XOR Direct")
circ3.add_xor(['A', 'B'], 'out')

print("=== Circuit Analysis ===")

for circ in [circ1, circ2, circ3]:
    print(f"\n{circ.name}:")
    print(f"  Gate count: {circ.gate_count()}")
    print(f"  Total: {circ.total_gates()} gates")

# Verify all circuits compute XOR
print("\n=== Verification (all should compute XOR) ===")
for a in [0, 1]:
    for b in [0, 1]:
        expected = a ^ b
        results = []
        for circ in [circ1, circ2, circ3]:
            result = circ.evaluate({'A': a, 'B': b})['out']
            results.append(result)

        all_correct = all(r == expected for r in results)
        status = "✓" if all_correct else "✗"
        print(f"  {status} A={a}, B={b}: expected={expected}, got={results}")

# Compare circuits
circ1.compare(circ2)
circ1.compare(circ3)
